CustomField.formula:
/* Donor Icon */ IF(AND(npo02__TotalOppAmount__c>0, npo02__TotalOppAmount__c<$Setup.NPBP_Options__c.Major_Donor_Threshold__c), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Contact_Donations_Report_ID__c & "/view?&fv0=" + Id, "/" & LEFT($Setup.NPBP_Options__c.Contact_Donations_Report_ID__c,15) & "?pv0=" +Id), IMAGE("/resource/Impact_Icons/Donor.png","Donor", 35, 35),"")+ " ",NULL)+
/* Major Donor Icon */ IF( npo02__TotalOppAmount__c>=$Setup.NPBP_Options__c.Major_Donor_Threshold__c, HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Contact_Donations_Report_ID__c & "/view?&fv0=" + Id, "/" & LEFT($Setup.NPBP_Options__c.Contact_Donations_Report_ID__c,15) & "?pv0=" +Id), IMAGE("/resource/Impact_Icons/Major.png","Major Donor", 35, 35),"")+ " ",NULL)+
/* Current Membership Icon */ IF(npo02__MembershipEndDate__c >= TODAY(), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Contact_Memberships_Report_ID__c & "/view?&fv0=" +Id, "/" & LEFT($Setup.NPBP_Options__c.Contact_Memberships_Report_ID__c, 15) & "?pv0=" +Id), IMAGE("/resource/Impact_Icons/Member.png","Member", 35, 35),"")+" ", NULL)+
/* Lapsed Membership Icon */ IF(npo02__MembershipEndDate__c<TODAY(), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Contact_Memberships_Report_ID__c & "/view?&fv0=" +Id, "/" & LEFT($Setup.NPBP_Options__c.Contact_Memberships_Report_ID__c, 15) & "?pv0=" +Id), IMAGE("/resource/Impact_Icons/FormerMember.png","Past Member", 35, 35),"")+" ",NULL)+
/* Do Not Contact Icon */ IF( npsp__Do_Not_Contact__c = TRUE, IMAGE("/resource/Impact_Icons/DoNotContact.png", "Do Not Contact", 35, 35)+" ",NULL)+
/* Board Member Icon */ IF( NPBPIsBoardMemberCheck__c=1, IMAGE("/resource/Impact_Icons/Board.png","Board Member", 35, 35)+" ",NULL)+
/* Do Not Take Pictures Icon */ IF( NPBPDo_Not_Take_Pictures__c= TRUE, IMAGE("/resource/Impact_Icons/DoNotTakePictures.png","Do Not Take Pictures", 35, 35)+" ",NULL)+
/* Deceased Icon */ IF( npsp__Deceased__c = TRUE, IMAGE("/resource/Impact_Icons/Deceased.png","Deceased", 35, 35),NULL)
